/**
 * A price calculation model containing net and gross amounts along with their associated tax details.
 */
export type CalculatedPrice = {
    /**
     * Net value of the price, price without tax.
     */
    netValue?: number;
    /**
     * Gross value of the price, price with tax.
     */
    grossValue?: number;
    /**
     * Tax value of the price, it's the actual amount of tax that has to be paid.
     */
    taxValue?: number;
    /**
     * Tax code applied to the price, a tax code is a country's set of tax rules.
     */
    taxCode?: string;
    /**
     * Tax rate applied to the price, it's the percentage at which an individual or business is taxed.
     */
    taxRate?: number;
};

export type CalculatedPriceWithDiscounts = CalculatedPrice & {
    /**
     * List of applied discounts for the calculated price.
     */
    appliedDiscounts?: Array<CalculatedAppliedDiscount>;
};

export type CalculatedPriceWithTaxAggregate = CalculatedPrice & {
    taxAggregate?: CalculatedTaxAggregate;
};

/**
 * Aggregated tax information showing detailed tax calculations
 */
export type CalculatedTaxAggregate = {
    /**
     * List of tax calculations grouped by taxCode and taxRate
     */
    lines?: Array<CalculatedPrice>;
};

/**
 * A breakdown of the total price calculated from all line items, including detailed pricing components.
 */
export type CartCalculatedPrice = {
    price?: CalculatedPrice & {
        /**
         * Net value of the price, price without tax.
         */
        netValue?: number;
        /**
         * Gross value of the price, price with tax.
         */
        grossValue?: number;
        /**
         * Tax value of the price, it's the actual amount of tax that has to be paid.
         */
        taxValue?: number;
        /**
         * Tax code applied to the price, a tax code is a country's set of tax rules. If all fees have the same taxRate, then the value is present. Otherwise, the field is not returned.
         */
        taxCode?: string;
        /**
         * Tax rate applied to the price, it's the percentage at which an individual or business is taxed. If all fees have the same taxRate, then the value is present. Otherwise, the field is not returned.
         */
        taxRate?: number;
    };
    upliftValue?: CalculatedPrice & {
        /**
         * Net value of the uplift amount, value without tax.
         */
        netValue?: number;
        /**
         * Gross value of the uplift amount, value with tax.
         */
        grossValue?: number;
        /**
         * Tax value of the uplift amount, it's the actual amount of tax that has to be paid.
         */
        taxValue?: number;
        /**
         * Tax code applied to uplift amount, a tax code is a country's set of tax rules. If all fees have the same taxRate, then the value is present. Otherwise, the field is not returned.
         */
        taxCode?: string;
        /**
         * Tax rate applied to the uplift amount, it's the percentage at which an individual or business is taxed. If all fees have the same taxRate, then the value is present. Otherwise, the field is not returned.
         */
        taxRate?: number;
    };
    discountedPrice?: CalculatedPriceWithDiscounts & {
        /**
         * The net value after applying discounts.
         */
        netValue?: number;
        /**
         * The gross value after applying discounts.
         */
        grossValue?: number;
        /**
         * The difference between `grossValue` and `netValue`.
         */
        taxValue?: number;
        /**
         * Tax code applied to the discounted price, a tax code is a country's set of tax rules. If all fees have the same taxRate, then the value is present. Otherwise, the field is not returned.
         */
        taxCode?: string;
        /**
         * Tax rate applied to the discounted price, it's the percentage at which an individual or business is taxed. If all fees have the same taxRate, then the value is present. Otherwise, the field is not returned.
         */
        taxRate?: number;
    };
    fees?: CalculatedPrice & {
        [key: string]: unknown;
    };
    totalFee?: CalculatedPriceWithDiscounts & {
        /**
         * Net value of the total fee, value without tax.
         */
        netValue?: number;
        /**
         * Gross value of the total fee, value with tax.
         */
        grossValue?: number;
        /**
         * Tax value of the total fee, it's the actual amount of tax that has to be paid.
         */
        taxValue?: number;
        /**
         * If all fees have the same `taxCode` defined, resulting in the same `taxRate`, the value is present. Otherwise, the field is not returned in the response.
         */
        taxRate?: number;
        /**
         * If all fees have the same `taxCode` defined, the value is present. Otherwise, the field is not returned in the response.
         */
        taxCode?: string;
        /**
         * A list of discounts applied to on the line item fees. The payment fee itself is not discountable.
         */
        appliedDiscounts?: unknown;
    };
    shipping?: CalculatedPrice & {
        [key: string]: unknown;
    };
    /**
     * The total shipping cost is calculated by summing `items[].calculatedPrice.price.grossValue` for shipping estimation. `GrossValue` is used because, even for zero-tax items, it remains equal to `netValue`. The `totalShipping` is the value *after all the discounts*, if any discounts were applied.
     */
    totalShipping?: CalculatedPriceWithDiscounts & {
        /**
         * The net value after applying discounts.
         */
        netValue?: number;
        /**
         * The gross value after applying discounts.
         */
        grossValue?: number;
        /**
         * The difference between `grossValue` and `netValue`.
         */
        taxValue?: number;
        /**
         * Tax code applied to the shipping cost, a tax code is a country's set of tax rules.
         */
        taxCode?: string;
        /**
         * Tax rate applied to the shipping cost, it's the percentage at which an individual or business is taxed.
         */
        taxRate?: number;
        /**
         * A list of discounts applied to shipping.
         */
        appliedDiscounts?: Array<CalculatedAppliedDiscount & {
            /**
             * Discount identifier.
             */
            id?: string;
            /**
             * Value of the discount that was applied.
             */
            value?: number;
            /**
             * PERCENT for percentage discounts and ABSOLUTE for amount applied to the line item.
             */
            discountType?: 'PERCENT' | 'ABSOLUTE' | 'FREE_SHIPPING';
        }>;
    };
    totalDiscount?: CalculatedTotalDiscount & {
        /**
         * Indicates whether discounts were applied to net or gross values.
         */
        calculationType?: 'ApplyDiscountBeforeTax' | 'ApplyDiscountAfterTax';
        /**
         * Aggregated sum of `lines[].calculatedPrice.totalDiscount.value` plus the sum of shipping discounts `totalShipping.appliedDiscounts[].value`.
         */
        value?: number;
        /**
         * A list of the applied discounts.
         */
        appliedDiscounts?: Array<CalculatedAppliedDiscount & {
            /**
             * Discount identifier.
             */
            id?: string;
            /**
             * The sum of all `lines[].calculatedPrice.totalDiscount.value` plus `totalShipping.appliedDiscounts[].value` grouped by the discount ID.
             */
            value?: number;
            /**
             * PERCENT for percentage discounts, ABSOLUTE for monetary amount and FREE_SHIPPING is shipping is fully discounted.
             */
            discountType?: 'PERCENT' | 'ABSOLUTE' | 'FREE_SHIPPING';
        }>;
    };
    finalPrice?: CalculatedPriceWithTaxAggregate & {
        /**
         * The sum of line items, `discountedPrice.netValue` or `price.netValue`, and `totalFee.netValue`.
         */
        netValue?: number;
        /**
         * The sum of line items, `discountedPrice.grossValue` or `price.grossValue`, and `totalFee.grossValue`.
         */
        grossValue?: number;
        /**
         * The result of subtracting `netValue` and `grossValue`, which is equal to the sum of all `taxValues` from the prices.
         */
        taxValue?: number;
        /**
         * If the tax code of the line item matches the tax code of all applied fees, the tax rate is populated with the value. Otherwise, it's not returned in the response.
         */
        taxRate?: number;
        /**
         * The common tax code of the line item and all applicable fees. If at least one fee does not have a defined tax code, the common tax code cannot be determined, and the field is empty.
         */
        taxCode?: string;
        taxAggregate?: {
            lines?: CalculatedPrice & {
                /**
                 * Net value of the tax, value without tax.
                 */
                netValue?: number;
                /**
                 * Gross value of the tax, value with tax.
                 */
                grossValue?: number;
                /**
                 * Tax value of the tax, it's the actual amount of tax that has to be paid.
                 */
                taxValue?: number;
                /**
                 * Tax code applied to the tax, a tax code is a country's set of tax rules.
                 */
                taxCode?: string;
                /**
                 * Tax rate applied to the tax, it's the percentage at which an individual or business is taxed.
                 */
                taxRate?: number;
            };
        };
    };
};

